#include<bits/stdc++.h>
#define ll long long
#define MIN -0x3f3f3f3f
using namespace std;
const int MAXN=1e2+5;
int n,m,a[MAXN][MAXN];char c;
int main(void){
	//freopen("mine.in","r",stdin);
	//freopen("mine.out","w",stdout);
	memset(a,0,sizeof(a));
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;++i){
		for(int j=1;j<=m;++j){
			cin>>c;
			if(c=='*')a[i][j]=MIN,++a[i+1][j+1],++a[i+1][j],++a[i+1][j-1],++a[i][j+1],++a[i][j-1],++a[i-1][j+1],++a[i-1][j],++a[i-1][j-1];
		}
	}for(int i=1;i<=n;++i){
		for(int j=1;j<=m;++j)putchar(((a[i][j]<0)?('*'):(char(a[i][j]+'0'))));
		putchar('\n');
	}
	return false;
}
